// ── LOGIN MODAL ──
function renderModal() {
  return `<div class="modal-overlay" id="loginModal" onclick="if(event.target===this)closeLogin()">
  <div class="modal">
    <button class="close" onclick="closeLogin()">×</button>
    <h2>Espace Client - Connexion</h2>
    <div class="modal-field">
      <label>Adresse Email</label>
      <input type="email" placeholder="votre@email.com">
    </div>
    <div class="modal-field">
      <label>Mot de Passe</label>
      <input type="password" placeholder="••••••••">
    </div>
    <div class="modal-check">
      <input type="checkbox" id="remember">
      <label for="remember">Se souvenir de moi</label>
    </div>
    <a class="modal-forgot">Mot de passe oublié ?</a>
    <button class="modal-btn">Se Connecter</button>
    <p class="modal-register">Pas encore de compte ? <a href="#">Créer un compte</a></p>
  </div>
</div>`;
}

// ── DEVIS SECTION (shared on most pages) ──
function renderDevis() {
  return `<section class="devis-section" id="devis">
  <div class="wrap">
    <div class="devis-inner">
      <div class="devis-left">
        <h2>DEMANDEZ UN DEVIS</h2>
        <h3>Besoin d'un devis gratuit ? N'hésitez pas à nous contacter</h3>
        <div class="devis-tags">
          <span class="devis-tag">✓ Répondre dans les 24 heures</span>
          <span class="devis-tag">✓ Assistance téléphonique 24h/24</span>
        </div>
        <p>Nous vous invitons à prendre contact avec nous afin d'obtenir une estimation gratuite des coûts pour un projet ou un service spécifique. Nous sommes ouverts à fournir des informations supplémentaires et à répondre à toutes les questions avant de formaliser une offre payante.</p>
        <p>Appelez pour en savoir plus</p>
        <div class="devis-phone"><a href="tel:+61 485 976 4090">+61 485 976 4090</a></div>
      </div>
      <div class="devis-right">
        <form onsubmit="submitDevis(event)">
          <select required>
            <option value="">Selectionnez un Service</option>
            <option>Gestions des biens</option>
            <option>Formations Spécialisées</option>
            <option>Convoyages diplomatiques</option>
            <option>Produits de sécurité</option>
            <option>Sécurité des Biens</option>
            <option>Récupération des données</option>
          </select>
          <input type="text" placeholder="Votre Nom Complet" required>
          <input type="email" placeholder="Votre Email" required>
          <input type="text" placeholder="Votre Téléphone">
          <textarea placeholder="Décrivez votre besoin..."></textarea>
          <button type="submit" class="devis-submit">Demandez un devis</button>
        </form>
      </div>
    </div>
  </div>
</section>`;
}

// ── TEAM SECTION (shared) ──
function renderTeam() {
  const members = [
    {img:'team-4',name:'John Anderson',role:'C.E.O'},
    {img:'team-2',name:'Sarah Mitchell',role:'Responsable Gestion des Biens'},
    {img:'team-3',name:'Benjamin Harris',role:'Respo. Transport'},
    {img:'team-1',name:'James Taylor',role:'Supervise la surveillance'},
    {img:'team-5',name:'Jessica Green',role:'Coordonne les flux de transport'},
    {img:'team-6',name:'Matthew Smith',role:'Respo. Relations clients'},
  ];
  return `<section class="section section-white">
  <div class="wrap">
    <div class="section-heading">
      <h2>MEMBRES DE L'ÉQUIPE</h2>
      <div class="gold-line"></div>
      <p>Des professionnels prêts à vous aider.</p>
    </div>
    <div class="team-grid">
      ${members.map(m=>`<div class="team-card">
        <div style="width:100%;aspect-ratio:1/1;background:linear-gradient(135deg,#001847,#000814);display:flex;align-items:center;justify-content:center;border:3px solid transparent;transition:border-color .3s" onmouseenter="this.style.borderColor='#c8a96e'" onmouseleave="this.style.borderColor='transparent'">
          <span style="font-family:'Cormorant Garamond',serif;font-size:48px;color:rgba(200,169,110,0.3)">${m.name.charAt(0)}</span>
        </div>
        <h4>${m.name}</h4>
        <span>${m.role.toUpperCase()}</span>
      </div>`).join('')}
    </div>
  </div>
</section>`;
}

